# INSIGHT: sort by pos desc; time-to-target comparison reveals fleets
cars = sorted(zip(position, speed), reverse=True)  # farthest first
stack = []
for pos, spd in cars:
    time = (target - pos) / spd
    if not stack or time > stack[-1]:
        stack.append(time)  # new fleet
    # else: this car catches fleet ahead → same fleet, don't push
return len(stack)
# Time: O(n log n) for sort  Space: O(n)
